// The previous attempt asserted facts (e.g. `post1_self_.wf()`,
// `post1_self_@[p as int] =~= pre_self_@[p as int]`) that are part of
// the *antecedent* of this synthetic proof fn's ensures clause — i.e.
// they are NOT requires of `det_<f>` and therefore are not available as
// hypotheses anywhere inside the body. They only become hypotheses at
// function exit, when Verus discharges the implication
// `(ensures_conj) ==> det_<f>_equal(...)`. Hence the prior, unconditional
// `assert(post1_self_.wf())` and `assert(post2_self_.wf())` failed.
//
// Repair: wrap the entire derivation in `if (ensures_conjunction) { ... }`.
// Inside the `if`, the conjunction is a live hypothesis, so we can
//   (a) instantiate both `forall|p|` ensures-foralls on the same `p`
//       (closing the disjoint-trigger gap on the non-pcid slots), and
//   (b) chain each per-projection equality at the `pcid` slot through
//       `pre_self_@[pcid as int].unwrap()` so the two runs agree on
//       every spec-pinned component.
// Verus lifts each `assert` inside the `if` to `ensures_conj ==> assert`
// outside the `if`. At function exit, the synthetic ensures-antecedent
// supplies `ensures_conj`, so z3 has every per-projection equality it
// needs to discharge `det_<f>_equal`.
if post1_self_.wf()
    && (forall|p: Pcid|
        #![trigger post1_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < PCID_MAX && p != pcid ==> post1_self_@[p as int] =~= pre_self_@[p as int])
    && post1_self_@[pcid as int].is_Some()
    && post1_self_@[pcid as int].unwrap().wf()
    && post1_self_@[pcid as int].unwrap().pcid == pre_self_@[pcid as int].unwrap().pcid
    && post1_self_@[pcid as int].unwrap().kernel_l4_end == pre_self_@[pcid as int].unwrap().kernel_l4_end
    && post1_self_@[pcid as int].unwrap().page_closure() =~= pre_self_@[pcid as int].unwrap().page_closure().insert(page_map_ptr)
    && post1_self_@[pcid as int].unwrap().mapping_4k() =~= pre_self_@[pcid as int].unwrap().mapping_4k()
    && post1_self_@[pcid as int].unwrap().mapping_2m() =~= pre_self_@[pcid as int].unwrap().mapping_2m()
    && post1_self_@[pcid as int].unwrap().mapping_1g() =~= pre_self_@[pcid as int].unwrap().mapping_1g()
    && post1_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some()
    && post1_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr == page_map_ptr
    && post1_self_@[pcid as int].unwrap().kernel_entries =~= pre_self_@[pcid as int].unwrap().kernel_entries
    && post2_self_.wf()
    && (forall|p: Pcid|
        #![trigger post2_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < PCID_MAX && p != pcid ==> post2_self_@[p as int] =~= pre_self_@[p as int])
    && post2_self_@[pcid as int].is_Some()
    && post2_self_@[pcid as int].unwrap().wf()
    && post2_self_@[pcid as int].unwrap().pcid == pre_self_@[pcid as int].unwrap().pcid
    && post2_self_@[pcid as int].unwrap().kernel_l4_end == pre_self_@[pcid as int].unwrap().kernel_l4_end
    && post2_self_@[pcid as int].unwrap().page_closure() =~= pre_self_@[pcid as int].unwrap().page_closure().insert(page_map_ptr)
    && post2_self_@[pcid as int].unwrap().mapping_4k() =~= pre_self_@[pcid as int].unwrap().mapping_4k()
    && post2_self_@[pcid as int].unwrap().mapping_2m() =~= pre_self_@[pcid as int].unwrap().mapping_2m()
    && post2_self_@[pcid as int].unwrap().mapping_1g() =~= pre_self_@[pcid as int].unwrap().mapping_1g()
    && post2_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some()
    && post2_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr == page_map_ptr
    && post2_self_@[pcid as int].unwrap().kernel_entries =~= pre_self_@[pcid as int].unwrap().kernel_entries
{
    // Force both `forall|p|` ensures-foralls to fire on the same `p` and
    // chain them through `pre_self_@[p as int]` so the non-pcid slots
    // of post1 and post2 agree pointwise.
    assert forall|p: Pcid| 0 <= p < PCID_MAX && p != pcid implies
        post1_self_@[p as int] =~= post2_self_@[p as int] by {
        assert(post1_self_@[p as int] =~= pre_self_@[p as int]);
        assert(post2_self_@[p as int] =~= pre_self_@[p as int]);
    }

    // Per-projection equalities at the `pcid` slot: each side equals the
    // same `pre_self_@[pcid as int].unwrap()`-derived value, so they
    // equal each other.
    assert(post1_self_@[pcid as int].is_Some());
    assert(post2_self_@[pcid as int].is_Some());
    assert(post1_self_@[pcid as int].unwrap().pcid
        == post2_self_@[pcid as int].unwrap().pcid);
    assert(post1_self_@[pcid as int].unwrap().kernel_l4_end
        == post2_self_@[pcid as int].unwrap().kernel_l4_end);
    assert(post1_self_@[pcid as int].unwrap().page_closure()
        =~= post2_self_@[pcid as int].unwrap().page_closure());
    assert(post1_self_@[pcid as int].unwrap().mapping_4k()
        =~= post2_self_@[pcid as int].unwrap().mapping_4k());
    assert(post1_self_@[pcid as int].unwrap().mapping_2m()
        =~= post2_self_@[pcid as int].unwrap().mapping_2m());
    assert(post1_self_@[pcid as int].unwrap().mapping_1g()
        =~= post2_self_@[pcid as int].unwrap().mapping_1g());
    assert(post1_self_@[pcid as int].unwrap().kernel_entries
        =~= post2_self_@[pcid as int].unwrap().kernel_entries);
    assert(post1_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some());
    assert(post2_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some());
    assert(post1_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr
        == post2_self_@[pcid as int].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr);
}

// Trivial unit-return equality so `r1 == r2` is in scope for the
// conjunction inside `det_..._equal`.
assert(r1 == r2);
